 97→    async (id: SourceId): Promise<void> => {
 98→      await sourceRepository.touch(id);
 99→      setSources((prev) =>
100→        prev.map((s) =>
101→          s.id === id ? { ...s, lastUsedAt: Date.now() } : s
102→        )
103→      );
104→    },
105→    []
106→  );
107→
108→  const getLastUsed = useCallback((): Source | null => {
109→    if (sources.length === 0) return null;
110→    const sorted = [...sources].sort((a, b) => b.lastUsedAt - a.lastUsedAt);
111→    const mostRecent = sorted[0];
112→    const isWithin24Hours =
113→      Date.now() - mostRecent.lastUsedAt < 24 * 60 * 60 * 1000;
114→    return isWithin24Hours ? mostRecent : null;
115→  }, [sources]);
116→
117→  const refresh = useCallback(async (): Promise<void> => {
118→    const freshSources = await sourceRepository.getAll();
119→    setSources(freshSources);
120→  }, []);
121→
122→  const value = useMemo(
123→    (): SourcesContextValue => ({
124→      sources,
125→      getSourceName,
126→      createSource,
127→      renameSource,
128→      setSourceLanguage,
129→      deleteSource,
130→      touchSource,
131→      getLastUsed,
132→      refresh,
133→    }),
134→    [
135→      sources,
136→      getSourceName,
137→      createSource,
138→      renameSource,
139→      setSourceLanguage,
140→      deleteSource,
141→      touchSource,
142→      getLastUsed,
143→      refresh,
144→    ]
145→  );
146→
147→  return (
148→    <SourcesContext.Provider value={value}>{children}</SourcesContext.Provider>
149→  );
150→}
