  async (id: RecipeId, metadata: RecipeMetadataWrite) => {
    const updatedRecipe = await recipeRepository.update(id, metadata);
    setRecipes((prev) =>
      prev.map((recipe) => (recipe.id === id ? updatedRecipe : recipe))
    );
    await refreshTags();
  },
  [refreshTags]
);

