 10→import Svg, { Defs, Ellipse, RadialGradient, Stop } from "react-native-svg";
 11→
 12→const ROTATING_KEYS = [
 13→  "m1",
 14→  "m2",
 15→  "m3",
 16→  "m4",
 17→  "m5",
 18→  "m6",
 19→  "m7",
 20→  "m8",
 21→  "m9",
 22→  "m10",
 23→] as const;
 24→
 25→const INTERVAL_MS = 3000;
 26→const FADE_DURATION_MS = 500;
 27→
 28→const ELLIPSE_WIDTH_RATIO = 0.8;
 29→const ELLIPSE_HEIGHT = 300;
 30→
 31→function VignetteOverlay(): JSX.Element {
 32→  const { width, height } = useWindowDimensions();
 33→  const cx = width / 2;
 34→  const cy = height / 2;
 35→  const rx = (width * ELLIPSE_WIDTH_RATIO) / 2;
 36→  const ry = ELLIPSE_HEIGHT / 2;
 37→
 38→  return (
 39→    <Svg style={StyleSheet.absoluteFill}>
 40→      <Defs>
 41→        <RadialGradient id="vignette" cx="50%" cy="50%" rx="50%" ry="50%">
 42→          <Stop offset="0" stopColor="black" stopOpacity="0.7" />
 43→          <Stop offset="1" stopColor="black" stopOpacity="0" />
 44→        </RadialGradient>
 45→      </Defs>
 46→      <Ellipse cx={cx} cy={cy} rx={rx} ry={ry} fill="url(#vignette)" />
 47→    </Svg>
 48→  );
 49→}
