29→export function useAddButtonFocusTransition(isSearchFocused: boolean): {
30→  addButtonOuterStyle: ViewStyle;
31→  addButtonInnerStyle: ViewStyle;
32→} {
33→  const visualProgress = useSharedValue(0);
34→  const collapseProgress = useSharedValue(0);
35→
36→  useEffect(() => {
37→    cancelAnimation(visualProgress);
38→    cancelAnimation(collapseProgress);
39→
40→    if (isSearchFocused) {
41→      visualProgress.value = withSpring(1, HIDE_VISUAL_SPRING_CONFIG);
42→      collapseProgress.value = withDelay(
43→        0,
44→        withTiming(1, {
45→          duration: HIDE_COLLAPSE_DURATION_MS,
46→        }),
47→      );
48→
49→      return;
50→    }
51→
52→    collapseProgress.value = withTiming(
53→      0,
54→      {
55→        duration: SHOW_COLLAPSE_DURATION_MS,
56→      },
57→      (isFinished) => {
58→        if (!isFinished) {
59→          return;
60→        }
61→
62→        visualProgress.value = withSpring(0, SHOW_VISUAL_SPRING_CONFIG);
63→      },
64→    );
65→  }, [collapseProgress, isSearchFocused, visualProgress]);
66→
67→  const addButtonOuterStyle = useAnimatedStyle(() => ({
68→    width: ADD_BUTTON_SIZE * (1 - collapseProgress.value),
69→    marginLeft: ADD_BUTTON_GAP * (1 - collapseProgress.value),
70→  }));
71→
72→  const addButtonInnerStyle = useAnimatedStyle(() => ({
73→    opacity: 1 - visualProgress.value,
74→    transform: [{ scale: 1 - visualProgress.value * 0.35 }],
75→  }));
76→
77→  return useMemo(
78→    () => ({
79→      addButtonOuterStyle,
80→      addButtonInnerStyle,
81→    }),
82→    [addButtonInnerStyle, addButtonOuterStyle],
83→  );
84→}
