  4→extension UIColor {
  5→  convenience init?(hexString: String) {
  6→    let hex = hexString.trimmingCharacters(in: CharacterSet.alphanumerics.inverted)
  7→    var int: UInt64 = 0
  8→    Scanner(string: hex).scanHexInt64(&int)
  9→    let a, r, g, b: UInt64
 10→    switch hex.count {
 11→    case 3:
 12→      (a, r, g, b) = (255, (int >> 8) * 17, (int >> 4 & 0xF) * 17, (int & 0xF) * 17)
 13→    case 6:
 14→      (a, r, g, b) = (255, int >> 16, int >> 8 & 0xFF, int & 0xFF)
 15→    case 8:
 16→      (a, r, g, b) = (int >> 24, int >> 16 & 0xFF, int >> 8 & 0xFF, int & 0xFF)
 17→    default:
 18→      return nil
 19→    }
 20→    self.init(
 21→      red: CGFloat(r) / 255,
 22→      green: CGFloat(g) / 255,
 23→      blue: CGFloat(b) / 255,
 24→      alpha: CGFloat(a) / 255
 25→    )
 26→  }
 27→}
