struct LiquidGlassButtonContent: View {
  var systemImage: String
  var imageSize: CGFloat
  var imageScale: CGFloat
  var fontSize: CGFloat
  var containerSize: CGFloat
  var tintColor: UIColor?
  var fillColor: UIColor?
  var fillProgress: CGFloat
  var isLoading: Bool
  var onPress: () -> Void

  private var resolvedFillColor: Color {
    if let fillColor = fillColor {
      return Color(fillColor)
    }
    if let tintColor = tintColor {
      return Color(tintColor)
    }
    return Color.blue
  }

  private func fillOverlay(diameter: CGFloat) -> some View {
    GeometryReader { geo in
      Rectangle()
        .fill(resolvedFillColor.opacity(0.3))
        .frame(width: geo.size.width * fillProgress)
        .frame(maxHeight: .infinity, alignment: .leading)
    }
    .frame(width: diameter, height: diameter)
    .clipShape(Circle())
    .allowsHitTesting(false)
  }

  private var iconContent: some View {
    Group {
      if isLoading {
        ProgressView()
          .progressViewStyle(.circular)
          .tint(tintColor.map { Color($0) } ?? .primary)
      } else {
        Image(systemName: systemImage)
          .font(.system(size: fontSize * imageScale))
          .foregroundStyle(tintColor.map { Color($0) } ?? .primary)
      }
    }
    .frame(width: imageSize, height: imageSize)
    .animation(.easeInOut(duration: 0.3), value: isLoading)
  }

  var body: some View {
    GeometryReader { geometry in
      if #available(iOS 26.0, *) {
        Button(action: onPress) {
          ZStack {
            if fillProgress > 0 {
              fillOverlay(diameter: imageSize)
            }
            iconContent
          }
        }
        .buttonBorderShape(.circle)
        .buttonStyle(.glass)
        .disabled(isLoading)
        .position(x: geometry.size.width / 2, y: geometry.size.height / 2)
      } else {
        Button(action: onPress) {
          ZStack {
            if fillProgress > 0 {
              fillOverlay(diameter: imageSize)
            }
            iconContent
          }
        }
        .background {
          Circle()
            .fill(.ultraThinMaterial)
        }
        .buttonStyle(.plain)
        .disabled(isLoading)
        .position(x: geometry.size.width / 2, y: geometry.size.height / 2)
      }
    }
    .frame(width: containerSize, height: containerSize)
  }
}
